{
    "level": "A2–B1",
    "intro": "У цій темі ти навчишся будувати <strong>subject questions</strong> — питання про того, <strong>хто</strong> або <strong>що</strong> виконує дію.",
    "rules": [
        {
            "label": "WHO / WHAT AS SUBJECT",
            "color": "emerald",
            "text": "Коли <strong>who</strong> або <strong>what</strong> є підметом, вони самі стоять на місці subject:",
            "example": "Who called you? / What happened?"
        },
        {
            "label": "NO DO / DOES / DID",
            "color": "blue",
            "text": "У звичайному subject question ми <strong>не додаємо do / does / did</strong>.",
            "example": "Who lives here? not Who does live here?"
        },
        {
            "label": "OBJECT QUESTION = DIFFERENT",
            "color": "amber",
            "text": "Якщо питальне слово не є підметом, це вже <strong>object question</strong> і там часто потрібен auxiliary.",
            "example": "Who called you? vs Who did you call?"
        }
    ]
}

{
    "title": "1. Базова модель",
    "intro": "Порівняй subject questions і object questions.",
    "items": [
        {
            "label": "Subject question",
            "title": "Who called you?",
            "subtitle": "who = підмет, без did"
        },
        {
            "label": "Object question",
            "title": "Who did you call?",
            "subtitle": "who = додаток, потрібен did"
        },
        {
            "label": "Базова формула",
            "title": "Who / What + verb + ...?",
            "subtitle": "Who wants coffee? / What caused the problem?"
        },
        {
            "label": "Головне правило",
            "title": "no inversion, no do-support",
            "subtitle": "порядок ближчий до звичайного твердження"
        }
    ]
}

{
    "title": "2. Як працюють subject questions",
    "sections": [
        {
            "label": "Who як підмет",
            "color": "emerald",
            "description": "Коли ми не знаємо, <strong>яка людина</strong> зробила дію, використовуємо <strong>who</strong> як subject.",
            "examples": [
                {
                    "en": "Who called you last night?",
                    "ua": "Хто подзвонив тобі вчора ввечері?"
                },
                {
                    "en": "Who lives in that house?",
                    "ua": "Хто живе в тому будинку?"
                },
                {
                    "en": "Who wants some tea?",
                    "ua": "Хто хоче чаю?"
                }
            ]
        },
        {
            "label": "What як підмет",
            "color": "blue",
            "description": "Коли питаємо про <strong>річ, подію або причину</strong>, яка є subject, беремо <strong>what</strong>.",
            "examples": [
                {
                    "en": "What happened?",
                    "ua": "Що сталося?"
                },
                {
                    "en": "What made you laugh?",
                    "ua": "Що змусило тебе засміятися?"
                },
                {
                    "en": "What caused the delay?",
                    "ua": "Що спричинило затримку?"
                }
            ]
        },
        {
            "label": "Контраст із object questions",
            "color": "amber",
            "description": "Постав собі питання: <strong>хто робить дію</strong> чи <strong>на кого спрямована дія</strong>? Це вирішує структуру.",
            "examples": [
                {
                    "en": "Who called you?",
                    "ua": "Хто тобі подзвонив?"
                },
                {
                    "en": "Who did you call?",
                    "ua": "Кому ти подзвонив?"
                },
                {
                    "en": "What broke the window?",
                    "ua": "Що розбило вікно?"
                },
                {
                    "en": "What did you break?",
                    "ua": "Що ти розбив?"
                }
            ],
            "note": "Якщо wh-word = subject, не додаємо do / does / did."
        }
    ]
}

{
    "title": "3. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Додавати do / does / did у subject question.",
            "wrong": "Who did call you?",
            "right": "✅ <span class=\"font-mono\">Who called you?</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Плутати subject question з object question.",
            "wrong": "Who called you? = Кому ти подзвонив?",
            "right": "✅ <span class=\"font-mono\">Who did you call?</span> = Кому ти подзвонив?"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Ставити інверсію після what.",
            "wrong": "What did happen?",
            "right": "✅ <span class=\"font-mono\">What happened?</span>"
        }
    ]
}

